1	//======================================================================
2	//
3	// tb_aes.v
4	// --------
5	// Testbench for the aes top level wrapper.
6	//
7	//
8	//======================================================================
9	
10	
11	//------------------------------------------------------------------
12	// Test module.
13	//------------------------------------------------------------------
14	module tb_aes();
15	
16	  //----------------------------------------------------------------
17	  // Internal constant and parameter definitions.
18	  //----------------------------------------------------------------
19	  parameter DEBUG     = 0;
20	
21	  parameter CLK_HALF_PERIOD = 1;
22	  parameter CLK_PERIOD      = 2 * CLK_HALF_PERIOD;
23	
24	  // The DUT address map.
25	  parameter ADDR_NAME0       = 8'h00;
26	  parameter ADDR_NAME1       = 8'h01;
27	  parameter ADDR_VERSION     = 8'h02;
28	
29	  parameter ADDR_CTRL        = 8'h08;
30	  parameter CTRL_INIT_BIT    = 0;
31	  parameter CTRL_NEXT_BIT    = 1;
32	  parameter CTRL_ENCDEC_BIT  = 2;
33	  parameter CTRL_KEYLEN_BIT  = 3;
34	
35	  parameter ADDR_STATUS      = 8'h09;
36	  parameter STATUS_READY_BIT = 0;
37	  parameter STATUS_VALID_BIT = 1;
38	
39	  parameter ADDR_CONFIG      = 8'h0a;
40	
41	  parameter ADDR_KEY0        = 8'h10;
42	  parameter ADDR_KEY1        = 8'h11;
43	  parameter ADDR_KEY2        = 8'h12;
44	  parameter ADDR_KEY3        = 8'h13;
45	  parameter ADDR_KEY4        = 8'h14;
46	  parameter ADDR_KEY5        = 8'h15;
47	  parameter ADDR_KEY6        = 8'h16;
48	  parameter ADDR_KEY7        = 8'h17;
49	
50	  parameter ADDR_BLOCK0      = 8'h20;
51	  parameter ADDR_BLOCK1      = 8'h21;
52	  parameter ADDR_BLOCK2      = 8'h22;
53	  parameter ADDR_BLOCK3      = 8'h23;
54	
55	  parameter ADDR_RESULT0     = 8'h30;
56	  parameter ADDR_RESULT1     = 8'h31;
57	  parameter ADDR_RESULT2     = 8'h32;
58	  parameter ADDR_RESULT3     = 8'h33;
59	
60	  parameter AES_128_BIT_KEY = 0;
61	  parameter AES_256_BIT_KEY = 1;
62	
63	  parameter AES_DECIPHER = 1'b0;
64	  parameter AES_ENCIPHER = 1'b1;
65	
66	
67	  //----------------------------------------------------------------
68	  // Register and Wire declarations.
69	  //----------------------------------------------------------------
70	  reg [31 : 0]  cycle_ctr;
71	  reg [31 : 0]  error_ctr;
72	  reg [31 : 0]  tc_ctr;
73	
74	  reg [31 : 0]  read_data;
75	  reg [127 : 0] result_data;
76	
77	  reg           tb_clk;
78	  reg           tb_reset_n;
79	  reg           tb_cs;
80	  reg           tb_we;
81	  reg [7  : 0]  tb_address;
82	  reg [31 : 0]  tb_write_data;
83	  wire [31 : 0] tb_read_data;
84	
85	
86	  //----------------------------------------------------------------
87	  // Device Under Test.
88	  //----------------------------------------------------------------
89	  aes dut(
90	           .clk(tb_clk),
91	           .reset_n(tb_reset_n),
92	           .cs(tb_cs),
93	           .we(tb_we),
94	           .address(tb_address),
95	           .write_data(tb_write_data),
96	           .read_data(tb_read_data)
97	          );
98	
99	
100	  //----------------------------------------------------------------
101	  // clk_gen
102	  //
103	  // Always running clock generator process.
104	  //----------------------------------------------------------------
105	  always
106	    begin : clk_gen
107	      #CLK_HALF_PERIOD;
108	      tb_clk = !tb_clk;
109	    end // clk_gen
110	
111	
112	  //----------------------------------------------------------------
113	  // sys_monitor()
114	  //
115	  // An always running process that creates a cycle counter and
116	  // conditionally displays information about the DUT.
117	  //----------------------------------------------------------------
118	  always
119	    begin : sys_monitor
120	      cycle_ctr = cycle_ctr + 1;
121	
122	      #(CLK_PERIOD);
123	
124	      if (DEBUG)
125	        begin
126	          dump_dut_state();
127	        end
128	    end
129	
130	
131	  //----------------------------------------------------------------
132	  // dump_dut_state()
133	  //
134	  // Dump the state of the dump when needed.
135	  //----------------------------------------------------------------
136	  task dump_dut_state;
137	    begin
138	      $display("cycle: 0x%016x", cycle_ctr);
139	      $display("State of DUT");
140	      $display("------------");
141	      $display("ctrl_reg:   init   = 0x%01x, next   = 0x%01x", dut.init_reg, dut.next_reg);
142	      $display("config_reg: encdec = 0x%01x, length = 0x%01x ", dut.encdec_reg, dut.keylen_reg);
143	      $display("");
144	
145	      $display("block: 0x%08x, 0x%08x, 0x%08x, 0x%08x",
146	               dut.block_reg[0], dut.block_reg[1], dut.block_reg[2], dut.block_reg[3]);
147	      $display("");
148	
149	    end
150	  endtask // dump_dut_state
151	
152	
153	  //----------------------------------------------------------------
154	  // reset_dut()
155	  //
156	  // Toggle reset to put the DUT into a well known state.
157	  //----------------------------------------------------------------
158	  task reset_dut;
159	    begin
160	      $display("*** Toggle reset.");
161	      tb_reset_n = 0;
162	
163	      #(2 * CLK_PERIOD);
164	      tb_reset_n = 1;
165	      $display("");
166	    end
167	  endtask // reset_dut
168	
169	
170	  //----------------------------------------------------------------
171	  // display_test_results()
172	  //
173	  // Display the accumulated test results.
174	  //----------------------------------------------------------------
175	  task display_test_results;
176	    begin
177	      if (error_ctr == 0)
178	        begin
179	          $display("*** All %02d test cases completed successfully", tc_ctr);
180	        end
181	      else
182	        begin
183	          $display("*** %02d tests completed - %02d test cases did not complete successfully.",
184	                   tc_ctr, error_ctr);
185	        end
186	    end
187	  endtask // display_test_results
188	
189	
190	  //----------------------------------------------------------------
191	  // init_sim()
192	  //
193	  // Initialize all counters and testbed functionality as well
194	  // as setting the DUT inputs to defined values.
195	  //----------------------------------------------------------------
196	  task init_sim;
197	    begin
198	      cycle_ctr     = 0;
199	      error_ctr     = 0;
200	      tc_ctr        = 0;
201	
202	      tb_clk        = 0;
203	      tb_reset_n    = 1;
204	
205	      tb_cs         = 0;
206	      tb_we         = 0;
207	      tb_address    = 8'h0;
208	      tb_write_data = 32'h0;
209	    end
210	  endtask // init_sim
211	
212	
213	  //----------------------------------------------------------------
214	  // write_word()
215	  //
216	  // Write the given word to the DUT using the DUT interface.
217	  //----------------------------------------------------------------
218	  task write_word(input [11 : 0] address,
219	                  input [31 : 0] word);
220	    begin
221	      if (DEBUG)
222	        begin
223	          $display("*** Writing 0x%08x to 0x%02x.", word, address);
224	          $display("");
225	        end
226	
227	      tb_address = address;
228	      tb_write_data = word;
229	      tb_cs = 1;
230	      tb_we = 1;
231	      #(2 * CLK_PERIOD);
232	      tb_cs = 0;
233	      tb_we = 0;
234	    end
235	  endtask // write_word
236	
237	
238	  //----------------------------------------------------------------
239	  // write_block()
240	  //
241	  // Write the given block to the dut.
242	  //----------------------------------------------------------------
243	  task write_block(input [127 : 0] block);
244	    begin
245	      write_word(ADDR_BLOCK0, block[127  :  96]);
246	      write_word(ADDR_BLOCK1, block[95   :  64]);
247	      write_word(ADDR_BLOCK2, block[63   :  32]);
248	      write_word(ADDR_BLOCK3, block[31   :   0]);
249	    end
250	  endtask // write_block
251	
252	
253	  //----------------------------------------------------------------
254	  // read_word()
255	  //
256	  // Read a data word from the given address in the DUT.
257	  // the word read will be available in the global variable
258	  // read_data.
259	  //----------------------------------------------------------------
260	  task read_word(input [11 : 0]  address);
261	    begin
262	      tb_address = address;
263	      tb_cs = 1;
264	      tb_we = 0;
265	      #(CLK_PERIOD);
266	      read_data = tb_read_data;
267	      tb_cs = 0;
268	
269	      if (DEBUG)
270	        begin
271	          $display("*** Reading 0x%08x from 0x%02x.", read_data, address);
272	          $display("");
273	        end
274	    end
275	  endtask // read_word
276	
277	
278	  //----------------------------------------------------------------
279	  // read_result()
280	  //
281	  // Read the result block in the dut.
282	  //----------------------------------------------------------------
283	  task read_result;
284	    begin
285	      read_word(ADDR_RESULT0);
286	      result_data[127 : 096] = read_data;
287	      read_word(ADDR_RESULT1);
288	      result_data[095 : 064] = read_data;
289	      read_word(ADDR_RESULT2);
290	      result_data[063 : 032] = read_data;
291	      read_word(ADDR_RESULT3);
292	      result_data[031 : 000] = read_data;
293	    end
294	  endtask // read_result
295	
296	
297	  //----------------------------------------------------------------
298	  // init_key()
299	  //
300	  // init the key in the dut by writing the given key and
301	  // key length and then trigger init processing.
302	  //----------------------------------------------------------------
303	  task init_key(input [255 : 0] key, input key_length);
304	    begin
305	      if (DEBUG)
306	        begin
307	          $display("key length: 0x%01x", key_length);
308	          $display("Initializing key expansion for key: 0x%016x", key);
309	        end
310	
311	      write_word(ADDR_KEY0, key[255  : 224]);
312	      write_word(ADDR_KEY1, key[223  : 192]);
313	      write_word(ADDR_KEY2, key[191  : 160]);
314	      write_word(ADDR_KEY3, key[159  : 128]);
315	      write_word(ADDR_KEY4, key[127  :  96]);
316	      write_word(ADDR_KEY5, key[95   :  64]);
317	      write_word(ADDR_KEY6, key[63   :  32]);
318	      write_word(ADDR_KEY7, key[31   :   0]);
319	
320	      if (key_length)
321	        begin
322	          write_word(ADDR_CONFIG, 8'h02);
323	        end
324	      else
325	        begin
326	          write_word(ADDR_CONFIG, 8'h00);
327	        end
328	
329	      write_word(ADDR_CTRL, 8'h01);
330	
331	      #(100 * CLK_PERIOD);
332	    end
333	  endtask // init_key
334	
335	
336	  //----------------------------------------------------------------
337	  // ecb_mode_single_block_test()
338	  //
339	  // Perform ECB mode encryption or decryption single block test.
340	  //----------------------------------------------------------------
341	  task ecb_mode_single_block_test(input [7 : 0]   tc_number,
342	                                  input           encdec,
343	                                  input [255 : 0] key,
344	                                  input           key_length,
345	                                  input [127 : 0] block,
346	                                  input [127 : 0] expected);
347	    begin
348	      $display("*** TC %0d ECB mode test started.", tc_number);
349	      tc_ctr = tc_ctr + 1;
350	
351	      init_key(key, key_length);
352	      write_block(block);
353	      dump_dut_state();
354	
355	      write_word(ADDR_CONFIG, (8'h00 + (key_length << 1)+ encdec));
356	      write_word(ADDR_CTRL, 8'h02);
357	
358	      #(100 * CLK_PERIOD);
359	
360	      read_result();
361	
362	      if (result_data == expected)
363	        begin
364	          $display("*** TC %0d successful.", tc_number);
365	          $display("");
366	        end
367	      else
368	        begin
369	          $display("*** ERROR: TC %0d NOT successful.", tc_number);
370	          $display("Expected: 0x%032x", expected);
371	          $display("Got:      0x%032x", result_data);
372	          $display("");
373	
374	          error_ctr = error_ctr + 1;
375	        end
376	    end
377	  endtask // ecb_mode_single_block_test
378	
379	
380	  //----------------------------------------------------------------
381	  // aes_test()
382	  //
383	  // Main test task will perform complete NIST test of AES.
384	  //----------------------------------------------------------------
385	  task aes_test;
386	    reg [255 : 0] nist_aes128_key;
387	    reg [255 : 0] nist_aes256_key;
388	
389	    reg [127 : 0] nist_plaintext0;
390	    reg [127 : 0] nist_plaintext1;
391	    reg [127 : 0] nist_plaintext2;
392	    reg [127 : 0] nist_plaintext3;
393	
394	    reg [127 : 0] nist_ecb_128_enc_expected0;
395	    reg [127 : 0] nist_ecb_128_enc_expected1;
396	    reg [127 : 0] nist_ecb_128_enc_expected2;
397	    reg [127 : 0] nist_ecb_128_enc_expected3;
398	
399	    reg [127 : 0] nist_ecb_256_enc_expected0;
400	    reg [127 : 0] nist_ecb_256_enc_expected1;
401	    reg [127 : 0] nist_ecb_256_enc_expected2;
402	    reg [127 : 0] nist_ecb_256_enc_expected3;
403	
404	    begin
405	      nist_aes128_key = 256'h2b7e151628aed2a6abf7158809cf4f3c00000000000000000000000000000000;
406	      nist_aes256_key = 256'h603deb1015ca71be2b73aef0857d77811f352c073b6108d72d9810a30914dff4;
407	
408	      nist_plaintext0 = 128'h6bc1bee22e409f96e93d7e117393172a;
409	      nist_plaintext1 = 128'hae2d8a571e03ac9c9eb76fac45af8e51;
410	      nist_plaintext2 = 128'h30c81c46a35ce411e5fbc1191a0a52ef;
411	      nist_plaintext3 = 128'hf69f2445df4f9b17ad2b417be66c3710;
412	
413	      nist_ecb_128_enc_expected0 = 128'h3ad77bb40d7a3660a89ecaf32466ef97;
414	      nist_ecb_128_enc_expected1 = 128'hf5d3d58503b9699de785895a96fdbaaf;
415	      nist_ecb_128_enc_expected2 = 128'h43b1cd7f598ece23881b00e3ed030688;
416	      nist_ecb_128_enc_expected3 = 128'h7b0c785e27e8ad3f8223207104725dd4;
417	
418	      nist_ecb_256_enc_expected0 = 128'hf3eed1bdb5d2a03c064b5a7e3db181f8;
419	      nist_ecb_256_enc_expected1 = 128'h591ccb10d410ed26dc5ba74a31362870;
420	      nist_ecb_256_enc_expected2 = 128'hb6ed21b99ca6f4f9f153e7b1beafed1d;
421	      nist_ecb_256_enc_expected3 = 128'h23304b7a39f9f3ff067d8d8f9e24ecc7;
422	
423	
424	      $display("ECB 128 bit key tests");
425	      $display("---------------------");
426	      ecb_mode_single_block_test(8'h01, AES_ENCIPHER, nist_aes128_key, AES_128_BIT_KEY,
427	                                 nist_plaintext0, nist_ecb_128_enc_expected0);
428	
429	      ecb_mode_single_block_test(8'h02, AES_ENCIPHER, nist_aes128_key, AES_128_BIT_KEY,
430	                                nist_plaintext1, nist_ecb_128_enc_expected1);
431	
432	      ecb_mode_single_block_test(8'h03, AES_ENCIPHER, nist_aes128_key, AES_128_BIT_KEY,
433	                                 nist_plaintext2, nist_ecb_128_enc_expected2);
434	
435	      ecb_mode_single_block_test(8'h04, AES_ENCIPHER, nist_aes128_key, AES_128_BIT_KEY,
436	                                 nist_plaintext3, nist_ecb_128_enc_expected3);
437	
438	
439	      ecb_mode_single_block_test(8'h05, AES_DECIPHER, nist_aes128_key, AES_128_BIT_KEY,
440	                                 nist_ecb_128_enc_expected0, nist_plaintext0);
441	
442	      ecb_mode_single_block_test(8'h06, AES_DECIPHER, nist_aes128_key, AES_128_BIT_KEY,
443	                                 nist_ecb_128_enc_expected1, nist_plaintext1);
444	
445	      ecb_mode_single_block_test(8'h07, AES_DECIPHER, nist_aes128_key, AES_128_BIT_KEY,
446	                                 nist_ecb_128_enc_expected2, nist_plaintext2);
447	
448	      ecb_mode_single_block_test(8'h08, AES_DECIPHER, nist_aes128_key, AES_128_BIT_KEY,
449	                                 nist_ecb_128_enc_expected3, nist_plaintext3);
450	
451	
452	      $display("");
453	      $display("ECB 256 bit key tests");
454	      $display("---------------------");
455	      ecb_mode_single_block_test(8'h10, AES_ENCIPHER, nist_aes256_key, AES_256_BIT_KEY,
456	                                 nist_plaintext0, nist_ecb_256_enc_expected0);
457	
458	      ecb_mode_single_block_test(8'h11, AES_ENCIPHER, nist_aes256_key, AES_256_BIT_KEY,
459	                                 nist_plaintext1, nist_ecb_256_enc_expected1);
460	
461	      ecb_mode_single_block_test(8'h12, AES_ENCIPHER, nist_aes256_key, AES_256_BIT_KEY,
462	                                 nist_plaintext2, nist_ecb_256_enc_expected2);
463	
464	      ecb_mode_single_block_test(8'h13, AES_ENCIPHER, nist_aes256_key, AES_256_BIT_KEY,
465	                                 nist_plaintext3, nist_ecb_256_enc_expected3);
466	
467	
468	      ecb_mode_single_block_test(8'h14, AES_DECIPHER, nist_aes256_key, AES_256_BIT_KEY,
469	                                 nist_ecb_256_enc_expected0, nist_plaintext0);
470	
471	      ecb_mode_single_block_test(8'h15, AES_DECIPHER, nist_aes256_key, AES_256_BIT_KEY,
472	                                 nist_ecb_256_enc_expected1, nist_plaintext1);
473	
474	      ecb_mode_single_block_test(8'h16, AES_DECIPHER, nist_aes256_key, AES_256_BIT_KEY,
475	                                 nist_ecb_256_enc_expected2, nist_plaintext2);
476	
477	      ecb_mode_single_block_test(8'h17, AES_DECIPHER, nist_aes256_key, AES_256_BIT_KEY,
478	                                 nist_ecb_256_enc_expected3, nist_plaintext3);
479	    end
480	  endtask // aes_test
481	
482	
483	  //----------------------------------------------------------------
484	  // main
485	  //
486	  // The main test functionality.
487	  //----------------------------------------------------------------
488	  initial
489	    begin : main
490	      $display("   -= Testbench for AES started =-");
491	      $display("    ==============================");
492	      $display("");
493	
494	      init_sim();
495	      dump_dut_state();
496	      reset_dut();
497	      dump_dut_state();
498	
499	      aes_test();
500	
501	      display_test_results();
502	
503	      $display("");
504	      $display("*** AES simulation done. ***");
505	      $finish;
506	    end // main
507	endmodule // tb_aes
