93	  wire [127 : 0] core_result;
94	  wire           core_valid;
95	
96	
97	  //----------------------------------------------------------------
98	  // Concurrent connectivity for ports etc.
99	  //----------------------------------------------------------------
100	  assign read_data = tmp_read_data;
101	
102	  assign core_key = {key_reg[0], key_reg[1], key_reg[2], key_reg[3],
103	                     key_reg[4], key_reg[5], key_reg[6], key_reg[7]};
104	
105	  assign core_block  = {block_reg[0], block_reg[1],
106	                        block_reg[2], block_reg[3]};
107	  assign core_init   = init_reg;
108	  assign core_next   = next_reg;
109	  assign core_encdec = encdec_reg;
110	  assign core_keylen = keylen_reg;
111	
112	
113	  //----------------------------------------------------------------
114	  // core instantiation.
115	  //----------------------------------------------------------------
116	  aes_core core(
117	                .clk(clk),
118	                .reset_n(reset_n),
119	
120	                .encdec(core_encdec),
121	                .init(core_init),
122	                .next(core_next),
123	                .ready(core_ready),
124	
125	                .key(core_key),
126	                .keylen(core_keylen),
127	
128	                .block(core_block),
129	                .result(core_result),
130	                .result_valid(core_valid)
131	               );
