133	
134	  //----------------------------------------------------------------
135	  // reg_update
136	  // Update functionality for all registers in the core.
137	  // All registers are positive edge triggered with asynchronous
138	  // active low reset.
139	  //----------------------------------------------------------------
140	  always @ (posedge clk or negedge reset_n)
141	    begin : reg_update
142	      integer i;
143	
144	      if (!reset_n)
145	        begin
146	          for (i = 0 ; i < 4 ; i = i + 1)
147	            block_reg[i] <= 32'h0;
148	
149	          for (i = 0 ; i < 8 ; i = i + 1)
150	            key_reg[i] <= 32'h0;
151	
152	          init_reg   <= 1'b0;
153	          next_reg   <= 1'b0;
154	          encdec_reg <= 1'b0;
155	          keylen_reg <= 1'b0;
156	
157	          result_reg <= 128'h0;
158	          valid_reg  <= 1'b0;
159	          ready_reg  <= 1'b0;
160	        end
161	      else
162	        begin
163	          ready_reg  <= core_ready;
164	          valid_reg  <= core_valid;
165	          result_reg <= core_result;
166	          init_reg   <= init_new;
167	          next_reg   <= next_new;
168	
169	          if (config_we)
170	            begin
171	              encdec_reg <= write_data[CTRL_ENCDEC_BIT];
172	              keylen_reg <= write_data[CTRL_KEYLEN_BIT];
173	            end
174	
175	          if (key_we)
176	            key_reg[address[2 : 0]] <= write_data;
177	
178	          if (block_we)
179	            block_reg[address[1 : 0]] <= write_data;
180	        end
181	    end // reg_update
182	
183	
184	  //----------------------------------------------------------------
185	  // api
186	  //
187	  // The interface command decoding logic.
188	  //----------------------------------------------------------------
189	  always @*
190	    begin : api
191	      init_new      = 1'b0;
192	      next_new      = 1'b0;
193	      config_we     = 1'b0;
194	      key_we        = 1'b0;
195	      block_we      = 1'b0;
196	      tmp_read_data = 32'h0;
197	
198	      if (cs)
199	        begin
200	          if (we)
201	            begin
202	              if (address == ADDR_CTRL)
203	                begin
204	                  init_new = write_data[CTRL_INIT_BIT];
205	                  next_new = write_data[CTRL_NEXT_BIT];
206	                end
207	
208	              if (address == ADDR_CONFIG)
209	                config_we = 1'b1;
210	
211	              if ((address >= ADDR_KEY0) && (address <= ADDR_KEY7))
212	                key_we = 1'b1;
213	
214	              if ((address >= ADDR_BLOCK0) && (address <= ADDR_BLOCK3))
215	                block_we = 1'b1;
216	            end // if (we)
217	
218	          else
219	            begin
220	              case (address)
221	                ADDR_NAME0:   tmp_read_data = CORE_NAME0;
222	                ADDR_NAME1:   tmp_read_data = CORE_NAME1;
223	                ADDR_VERSION: tmp_read_data = CORE_VERSION;
224	                ADDR_CTRL:    tmp_read_data = {28'h0, keylen_reg, encdec_reg, next_reg, init_reg};
225	                ADDR_STATUS:  tmp_read_data = {30'h0, valid_reg, ready_reg};
226	
227	                default:
228	                  begin
229	                  end
230	              endcase // case (address)
231	
232	              if ((address >= ADDR_RESULT0) && (address <= ADDR_RESULT3))
233	                tmp_read_data = result_reg[(3 - (address - ADDR_RESULT0)) * 32 +: 32];
234	            end
235	        end
236	    end // addr_decoder
237	endmodule // aes
